142	
143	// Chrome do próprio Claude Code que vaza no excerpt (não é conteúdo do
144	// agente). Filtragem só aqui no display — `agent.pane_excerpt` continua
145	// intacto pros parsers (parseContextPct, parseModelFromPane) extraírem
146	// ctx%/modelo/tempo da linha de statusline.
147	//
148	// Validado contra 19 fixtures reais de tmux capture (DS-2 polish v2).
149	const CC_CHROME_PATTERNS: RegExp[] = [
150	  // Statusline: HH:MM ou HH:MM:SS, bar opcional, % no meio/fim, sufixo livre.
151	  // Pega tanto "Opus 4.7 - 32:13 - [█░] 16%" quanto a versão concatenada
152	  // com "Remote Control active" no fim da mesma linha.
153	  /^.*?\b(?:Opus|Sonnet|Haiku)\s+\d+\.\d+\b.*?\d+%/,
154	  // "Verb for Nm Ns" — spinner finalizado: ✻ Brewed, * Cogitated,
155	  // Considering, Thinking, Sautéed, Osmosing, Boogieing, Flibbertigibbeting…
156	  /^[\W]*\w+\s+for\s+\d+m?\s*\d*s?(\s*[·•].*)?\s*$/u,
157	  // Spinner ATIVO com contador de tokens:
158	  // "· Boogieing… (1m 8s · ↓ 2.7k tokens · thought for 33s)"
159	  /^[\s·•⏺]+\w+(?:ing|ed|aed)\.?…?\s*\(.*tokens.*\)$/u,
160	  // "Remote Control active" / "Remote Control connecting…" (qualquer estado).
161	  /Remote Control\s+\w+/,
162	  // "⏵⏵ bypass permissions on …" / "▶▶ bypass permissions …" — char varia
163	  // (U+23F5 vs U+25B6), catch por substring é mais seguro.
164	  /bypass permissions/,
165	];
166	
167	// Separador horizontal: 8+ chars consecutivos de box-drawing/block elements.
168	// Captura tanto "──────" puro quanto "── Daniel ──" (texto curto entre regras).
169	const SEPARATOR_RULE = /[─━═│┃╭╮╰╯╱╳─-╿▀-▟]{8,}/u;
170	
171	function isChromeLine(line: string): boolean {
172	  if (!line) return false;
173	  if (SEPARATOR_RULE.test(line)) return true;
174	  return CC_CHROME_PATTERNS.some((re) => re.test(line));
175	}
176	
177	function stripChrome(src: string): string {
178	  if (!src) return src;
179	  return src
180	    .split('\n')
181	    .map((line) => (isChromeLine(line) ? '' : line))
182	    .join('\n')
183	    .replace(/\n{3,}/g, '\n\n')
184	    .replace(/\n+$/, '');
185	}
186	
