194	  executorKind: string;
195	  connectionStatus: string;
196	  paused?: boolean;
197	}) {
198	  const preRef = useRef<HTMLPreElement>(null);
199	  const [stuck, setStuck] = useState(true);
200	
201	  useLayoutEffect(() => {
202	    const el = preRef.current;
203	    if (!el || !stuck) return;
204	    // paused (user digitando): chat fica imóvel — sem scroll involuntário.
205	    // Quando paused vira false (blur), efeito roda de novo e segue stuck-bottom.
206	    if (paused) return;
207	    el.scrollTop = el.scrollHeight;
208	  }, [excerpt, stuck, paused]);
209	
210	  const onScroll = useCallback(() => {
211	    const el = preRef.current;
212	    if (!el) return;
213	    const atBottom = el.scrollHeight - el.scrollTop - el.clientHeight < 24;
214	    setStuck(atBottom);
215	  }, []);
216	
217	  const goBottom = useCallback(() => {
218	    const el = preRef.current;
219	    if (!el) return;
220	    el.scrollTop = el.scrollHeight;
221	    setStuck(true);
222	  }, []);
223	
224	  const cleaned = useMemo(() => stripChrome(excerpt), [excerpt]);
225	  const empty = !cleaned;
